import{_ as r,X as h,Y as d,$ as a,a0 as n,a1 as t,a3 as e,F as p}from"./framework-abbf9d44.js";const s="/assets/image-20241110151318571-14db0f57.png",c="/assets/image-20241110154938097-f643da86.png",o="/assets/image-20241110163234152-2c15b964.png",l="/assets/image-20241112205251835-f7c10f88.png",f="/assets/image-20241113083225409-a669f5a8.png",g={},u=e('<h1 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h1><h2 id="做t" tabindex="-1"><a class="header-anchor" href="#做t" aria-hidden="true">#</a> 做T</h2><h3 id="压盘" tabindex="-1"><a class="header-anchor" href="#压盘" aria-hidden="true">#</a> 压盘</h3><figure><img src="'+s+'" alt="image-20241110151318571" tabindex="0" loading="lazy"><figcaption>image-20241110151318571</figcaption></figure><h3 id="托盘" tabindex="-1"><a class="header-anchor" href="#托盘" aria-hidden="true">#</a> 托盘</h3><figure><img src="'+c+'" alt="image-20241110154938097" tabindex="0" loading="lazy"><figcaption>image-20241110154938097</figcaption></figure><h3 id="口诀" tabindex="-1"><a class="header-anchor" href="#口诀" aria-hidden="true">#</a> 口诀</h3><figure><img src="'+o+'" alt="image-20241110163234152" tabindex="0" loading="lazy"><figcaption>image-20241110163234152</figcaption></figure><h3 id="macd" tabindex="-1"><a class="header-anchor" href="#macd" aria-hidden="true">#</a> MACD</h3><p>如何找比较确定的点位？心态，不要总想最高或者最低。相对来说有收益就很不错了</p><figure><img src="'+l+'" alt="高抛" tabindex="0" loading="lazy"><figcaption>高抛</figcaption></figure><figure><img src="'+f+'" alt="低吸" tabindex="0" loading="lazy"><figcaption>低吸</figcaption></figure><h2 id="李大霄" tabindex="-1"><a class="header-anchor" href="#李大霄" aria-hidden="true">#</a> 李大霄</h2><h3 id="高估的五类股票" tabindex="-1"><a class="header-anchor" href="#高估的五类股票" aria-hidden="true">#</a> 高估的五类股票</h3><p>小盘股，次新股，题材股，垃圾股，伪成长股。</p><p>这是李大霄老师所说的高估的五类股票：</p><ol><li>小盘股：通常指市值相对较小、流通盘较小的公司股票。这类股票容易被一些资金操控，股价波动较大，且很多小公司在经营上缺乏稳定性和可持续性，抗风险能力较弱。</li><li>次新股：是指刚上市不久的股票。次新股在上市初期往往会受到市场的追捧，股价容易出现大幅波动。而且，一些次新股的公司业绩还没有经过市场的充分检验，投资者对其未来的发展存在较大的不确定性。</li><li>题材股：是指那些因某一特定题材或概念而受到市场关注和炒作的股票。比如一些公司因涉及热门的科技概念、新能源概念等，在短期内股价大幅上涨，但很多时候这些公司的基本面并不能支撑其股价的长期上涨，一旦题材热度消退，股价往往会大幅下跌。</li><li>垃圾股：即业绩差、盈利能力差的公司股票。这类公司可能存在管理不善、市场竞争力不足、财务状况不佳等问题，难以给股东带来良好的回报，投资风险较高。</li><li>伪成长股：这类股票看似具有较高的成长性，但实际上其成长速度可能是虚假的或不可持续的。有些公司可能通过一些手段来美化财务报表，营造出高成长的假象，以吸引投资者买入，但最终可能无法实现预期的业绩增长，导致股价下跌。</li></ol><p>总的来说，李大霄老师认为投资者应该远离这些高估的五类股票，坚持价值投资，选择优质的、具有长期投资价值的公司股票。需要注意的是，股票市场是复杂多变的，对于股票的评估和判断也需要综合多方面因素进行分析。</p><h2 id="b站up-偏短线" tabindex="-1"><a class="header-anchor" href="#b站up-偏短线" aria-hidden="true">#</a> B站UP（偏短线）</h2>',19),b={href:"https://www.bilibili.com/video/BV1ew4m1m7bY",target:"_blank",rel:"noopener noreferrer"},m=e('<div class="hint-container danger"><p class="hint-container-title">注意</p><p>一定不要生搬硬套，要结合自己的操作习惯，市场状态灵活运用</p></div><h3 id="贪婪于恐惧" tabindex="-1"><a class="header-anchor" href="#贪婪于恐惧" aria-hidden="true">#</a> 贪婪于恐惧</h3><p>止盈止损的原则是，盈利15%，跌到10%就止盈。继续涨就继续拿，让盈利奔跑。</p><p>如果买入后跌了，亏损超过5%就止损。</p><p>如果能每次保证止盈10，止损5，操作100次，哪怕胜率只有50%，收益也将达到800%</p><h3 id="成交量" tabindex="-1"><a class="header-anchor" href="#成交量" aria-hidden="true">#</a> 成交量</h3><p>量比 小于 0.5，属于明显的缩量</p><blockquote><p>GTP: 量比的数值大小可以反映市场活跃度和资金流向。一般来说：</p><ul><li>量比为0.8-1.5倍，说明成交量处于正常水平。</li><li>量比在1.5-2.5倍之间为温和放量，可能表明市场对股票的兴趣在增加。</li><li>量比在2.5-5倍，则为明显放量，可能表明有较大的资金流入或流出。</li><li>量比达5-10倍，则为剧烈放量，可能是资金大规模流入或流出的迹象。</li><li>量比达到10倍以上的股票，一般可以考虑反向操作。</li><li>量比达到20倍以上的情形基本上每天都有一两单，是极端放量的一种表现。</li></ul><p>需要注意的是，量比的数值并不绝对，它需要结合市场情况和个股特性来综合分析</p></blockquote><h3 id="持有2-3-支股" tabindex="-1"><a class="header-anchor" href="#持有2-3-支股" aria-hidden="true">#</a> 持有2-3 支股</h3><p>散户的痛点是不会空仓，弱市急于补仓，本金少并且持有股票多，抱有侥幸的心理死扛到底。</p><h3 id="股市真理" tabindex="-1"><a class="header-anchor" href="#股市真理" aria-hidden="true">#</a> 股市真理</h3><p>早上大跌的，别急着割肉，下午通常会有反包。</p><p>尾盘大涨，要减仓，次日回调概率大。</p><p>缩量上涨，还会涨</p><p>缩量下跌，还会跌</p><p>放量滞涨，头部已现</p><p>缩量止跌，底部已现</p><p>巨量急涨，必然回调</p><h3 id="趋势为王" tabindex="-1"><a class="header-anchor" href="#趋势为王" aria-hidden="true">#</a> 趋势为王</h3><p>多头就是向上，空头向下</p><p>短线就看五日均线，放量突破就跟进。</p><p>中长线看20日均线。放量突破就跟进，破则出。</p><h3 id="买入分歧-卖出一致" tabindex="-1"><a class="header-anchor" href="#买入分歧-卖出一致" aria-hidden="true">#</a> 买入分歧 卖出一致</h3><blockquote><p>分歧： 连板的股票 出现炸板，放量等特征的时候。表示分歧</p></blockquote><p>当一强势的股票出现分歧的时候，就是买点，出现分歧之后，后续将继续上涨。</p><p>当所有人都觉得还能上涨的时候就是卖点。</p><h3 id="首阴反包要五个要点" tabindex="-1"><a class="header-anchor" href="#首阴反包要五个要点" aria-hidden="true">#</a> 首阴反包要五个要点</h3><p>第一点，要连板股，人气足，市场关注度高</p><p>第二条，首阴要杀得凶，市场分析要足够大，对他能反包的市场</p><p>第三条，巨阴杀跌过程，要满足两个条件。</p><p>​ 1：换手足</p><p>​ 2：筹码换手要集中在杀跌当天的相对低位，否则会导致次日反包到高位时，套牢盘的一致性卖压。</p><p>第四条，巨阴杀跌次日出现意味着预期反转的超预期平开或者高开。</p><p>第五条，首阴之日开始，调整不能超过三个交易日，否则人气会逐渐涣散。</p><h3 id="学会空仓" tabindex="-1"><a class="header-anchor" href="#学会空仓" aria-hidden="true">#</a> 学会空仓</h3><p>骄兵必败！！ 同时追两只兔子，最终一个也抓不到。</p><h3 id="控制心态" tabindex="-1"><a class="header-anchor" href="#控制心态" aria-hidden="true">#</a> 控制心态</h3><p>越是不顺，越要沉住气。扛得住涅槃之痛，配得上重生之美。</p><h3 id="审视自己" tabindex="-1"><a class="header-anchor" href="#审视自己" aria-hidden="true">#</a> 审视自己</h3><p>为什么做交易？</p><h3 id="回馈社会" tabindex="-1"><a class="header-anchor" href="#回馈社会" aria-hidden="true">#</a> 回馈社会</h3><p>炒股的成功者永远都是少数，所谓一将功成万骨枯当我们成功的时候，一定要记得做一些对社会有意义的事情，社会正是因为我们的互助才变得越来越美好</p>',42);function _(x,k){const i=p("ExternalLinkIcon");return h(),d("div",null,[u,a("p",null,[a("a",b,[n("https://www.bilibili.com/video/BV1ew4m1m7bY"),t(i)])]),m])}const v=r(g,[["render",_],["__file","大A.html.vue"]]);export{v as default};
